export const ASSET_SOURCES = {
  [ASSETS.court_bg]: courtBgSrc,
  [ASSETS.court_center_line]: courtCenterLineSrc,
  [ASSETS.paddle_player]: paddlePlayerSrc,
  [ASSETS.paddle_ai]: paddleAiSrc,
  [ASSETS.ball]: ballFramesSrc,
  [ASSETS.ball_shadow]: ballShadowSrc,
  [ASSETS.score_digits]: numbersScoreSrc,
  [ASSETS.text_win]: textWinSrc,
  [ASSETS.text_lose]: textLoseSrc,
  [ASSETS.btn_start]: btnStartSrc,
  [ASSETS.btn_again]: btnAgainSrc,
  [ASSETS.board]: boardSrc,
};

import { create } from 'zustand';

interface GameState {
  playerScore: number;
  aiScore: number;
  status: 'menu' | 'playing' | 'gameover';
  winner: 'player' | 'ai' | null;
  addPlayerScore: () => void;
  addAiScore: () => void;
  resetGame: () => void;
  setStatus: (status: 'menu' | 'playing' | 'gameover') => void;
  setWinner: (winner: 'player' | 'ai' | null) => void;
}

export const useGameStore = create<GameState>((set) => ({
  playerScore: 0,
  aiScore: 0,
  status: 'menu',
  winner: null,
  addPlayerScore: () => set((state) => ({ playerScore: state.playerScore + 1 })),
  addAiScore: () => set((state) => ({ aiScore: state.aiScore + 1 })),
  resetGame: () => set({ playerScore: 0, aiScore: 0, winner: null }),
  setStatus: (status) => set({ status }),
  setWinner: (winner) => set({ winner }),
}));

import Phaser from 'phaser';

export const EventBus = new Phaser.Events.EventEmitter();

export function startScene(scene: Phaser.Scene, key: string, data?: object) {
  if (!scene.scene.isActive(key)) {
    scene.scene.start(key, data);
    EventBus.emit('scene-changed', { key, data });
  }
}

import Phaser from 'phaser';
import { ASSETS, ASSET_SOURCES } from '../assets';

export default class Boot extends Phaser.Scene {
  constructor() {
    super('Boot');
  }

  preload() {
    // Generate fallback texture for load errors
    this.load.on('loaderror', (file: Phaser.Loader.File) => {
      const g = this.add.graphics();
      const w = this.game.config.width as number;
      const h = this.game.config.height as number;
      g.fillGradientStyle(0x667788, 0x334455, 0x334455, 0x667788);
      g.fillRect(0, 0, w, h);
      g.generateTexture(file.key, w, h);
      g.destroy();
    });

    this.load.image(ASSETS.court_bg, ASSET_SOURCES[ASSETS.court_bg]);
    this.load.image(ASSETS.court_center_line, ASSET_SOURCES[ASSETS.court_center_line]);
    this.load.image(ASSETS.paddle_player, ASSET_SOURCES[ASSETS.paddle_player]);
    this.load.image(ASSETS.paddle_ai, ASSET_SOURCES[ASSETS.paddle_ai]);

    this.load.spritesheet(ASSETS.ball, ASSET_SOURCES[ASSETS.ball], { frameWidth: 48, frameHeight: 48 });
    this.load.image(ASSETS.ball_shadow, ASSET_SOURCES[ASSETS.ball_shadow]);
    this.load.spritesheet(ASSETS.score_digits, ASSET_SOURCES[ASSETS.score_digits], { frameWidth: 51, frameHeight: 96 });

    this.load.image(ASSETS.text_win, ASSET_SOURCES[ASSETS.text_win]);
    this.load.image(ASSETS.text_lose, ASSET_SOURCES[ASSETS.text_lose]);
    this.load.image(ASSETS.btn_start, ASSET_SOURCES[ASSETS.btn_start]);
    this.load.image(ASSETS.btn_again, ASSET_SOURCES[ASSETS.btn_again]);
    this.load.image(ASSETS.board, ASSET_SOURCES[ASSETS.board]);
  }

  create() {
    this.anims.create({
      key: 'ball_spin',
      frames: this.anims.generateFrameNumbers(ASSETS.ball, { start: 0, end: 5 }),
      frameRate: 12,
      repeat: -1
    });

    this.scene.start('StartScene');
  }
}

import Phaser from 'phaser';
import { ASSETS } from '../assets';
import { startScene } from '../EventBus';
import { CONSTANTS } from '../constants';
import { useGameStore } from '../model/store';

export default class StartScene extends Phaser.Scene {
  constructor() {
    super('StartScene');
  }

  create() {
    // According to aesthetic template: Pure black background
    this.add.rectangle(0, 0, CONSTANTS.WIDTH, CONSTANTS.HEIGHT, 0x000000).setOrigin(0);

    // Title
    const title = this.add.text(CONSTANTS.WIDTH / 2, CONSTANTS.HEIGHT * 0.3, 'K12 乒乓球', {
      fontFamily: 'monospace',
      fontSize: '64px',
      color: '#39FF14'
    }).setOrigin(0.5);

    // Start Button (Using asset tinted to green, or just a text to match aesthetic)
    const startBtn = this.add.image(CONSTANTS.WIDTH / 2, CONSTANTS.HEIGHT * 0.6, ASSETS.btn_start)
      .setDisplaySize(145, 310)
      .setInteractive()
      .setTint(0x39FF14); // Apply neon green to the start button

    // Blinking effect for start button
    this.tweens.add({
      targets: startBtn,
      alpha: { from: 1, to: 0 },
      duration: 500,
      ease: 'Stepped', // 8-bit feel
      easeParams: [1],
      yoyo: true,
      repeat: -1
    });

    startBtn.on('pointerdown', () => {
      useGameStore.getState().resetGame();
      startScene(this, 'GameScene');
    });

    // Alternatively, allow pressing Space to start
    this.input.keyboard?.once('keydown-SPACE', () => {
      useGameStore.getState().resetGame();
      startScene(this, 'GameScene');
    });
  }
}

import Phaser from 'phaser';
import { ASSETS } from '../assets';
import { CONSTANTS } from '../constants';
import { useGameStore } from '../model/store';
import { startScene } from '../EventBus';

export default class GameScene extends Phaser.Scene {
  private playerPaddle!: Phaser.Physics.Arcade.Image;
  private aiPaddle!: Phaser.Physics.Arcade.Image;
  private ball!: Phaser.Physics.Arcade.Sprite;
  private ballShadow!: Phaser.GameObjects.Image;
  private cursors!: Phaser.Types.Input.Keyboard.CursorKeys;
  private playerScoreImg!: Phaser.GameObjects.Image;
  private aiScoreImg!: Phaser.GameObjects.Image;

  private currentBallSpeed: number = CONSTANTS.BALL_INITIAL_SPEED;
  private hitCount: number = 0;
  private isGameOver: boolean = false;
  private lastScoreRef: { player: number, ai: number } = { player: 0, ai: 0 };

  constructor() {
    super('GameScene');
  }

  create() {
    this.isGameOver = false;
    this.currentBallSpeed = CONSTANTS.BALL_INITIAL_SPEED;
    this.hitCount = 0;
    this.lastScoreRef = { player: 0, ai: 0 };

    // Pure black background for retro feel
    this.add.rectangle(0, 0, CONSTANTS.WIDTH, CONSTANTS.HEIGHT, 0x000000).setOrigin(0);

    // Center line (dashed)
    this.add.image(CONSTANTS.WIDTH / 2, CONSTANTS.HEIGHT / 2, ASSETS.court_center_line)
      .setDisplaySize(10, CONSTANTS.HEIGHT)
      .setTint(0x39FF14) // Neon green
      .setAlpha(0.5);

    // Player Paddle (Left)
    this.playerPaddle = this.physics.add.image(60, CONSTANTS.HEIGHT / 2, ASSETS.paddle_player)
      .setDisplaySize(CONSTANTS.PADDLE_WIDTH, CONSTANTS.PADDLE_HEIGHT)
      .setTintFill(0x39FF14); // Pure green solid block
    this.playerPaddle.setImmovable(true);
    (this.playerPaddle.body as Phaser.Physics.Arcade.Body).setAllowGravity(false);
    this.playerPaddle.setCollideWorldBounds(true);

    // AI Paddle (Right)
    this.aiPaddle = this.physics.add.image(CONSTANTS.WIDTH - 60, CONSTANTS.HEIGHT / 2, ASSETS.paddle_ai)
      .setDisplaySize(CONSTANTS.PADDLE_WIDTH, CONSTANTS.PADDLE_HEIGHT)
      .setTintFill(0xFF3333); // Pure red solid block
    this.aiPaddle.setImmovable(true);
    (this.aiPaddle.body as Phaser.Physics.Arcade.Body).setAllowGravity(false);
    this.aiPaddle.setCollideWorldBounds(true);

    // Ball
    this.ball = this.physics.add.sprite(CONSTANTS.WIDTH / 2, CONSTANTS.HEIGHT / 2, ASSETS.ball, 0)
      .setDisplaySize(CONSTANTS.BALL_SIZE, CONSTANTS.BALL_SIZE)
      .setTintFill(0x39FF14); // Pure green solid block for the ball
    this.ball.setBounce(1, 1);
    this.ball.setCollideWorldBounds(true);
    (this.ball.body as Phaser.Physics.Arcade.Body).onWorldBounds = true;

    // Play ball spin animation
    this.ball.play('ball_spin');

    // Input
    if (this.input.keyboard) {
      this.cursors = this.input.keyboard.createCursorKeys();
      this.input.keyboard.addCapture('UP,DOWN');
    }

    // Score HUD
    this.playerScoreImg = this.add.image(CONSTANTS.WIDTH / 2 - 100, 80, ASSETS.score_digits, 0)
      .setDisplaySize(51, 96)
      .setTint(0x39FF14);

    this.aiScoreImg = this.add.image(CONSTANTS.WIDTH / 2 + 100, 80, ASSETS.score_digits, 0)
      .setDisplaySize(51, 96)
      .setTint(0xFF3333);

    // Collisions
    this.physics.add.collider(this.ball, this.playerPaddle, this.handlePaddleHit, undefined, this);
    this.physics.add.collider(this.ball, this.aiPaddle, this.handlePaddleHit, undefined, this);

    // Bounds collision for scoring
    this.physics.world.on('worldbounds', (body: Phaser.Physics.Arcade.Body, up: boolean, down: boolean, left: boolean, right: boolean) => {
      if (this.isGameOver) return;
      if (left) {
        this.handleScore('ai');
      } else if (right) {
        this.handleScore('player');
      }
    });

    useGameStore.getState().setStatus('playing');

    // Start round
    this.time.delayedCall(1000, () => {
      this.resetBall(-1);
    });
  }

  private handlePaddleHit(ballObj: Phaser.Types.Physics.Arcade.GameObjectWithBody | Phaser.Tilemaps.Tile, paddleObj: Phaser.Types.Physics.Arcade.GameObjectWithBody | Phaser.Tilemaps.Tile) {
    if (this.isGameOver) return;

    const ball = ballObj as Phaser.Physics.Arcade.Sprite;
    const paddle = paddleObj as Phaser.Physics.Arcade.Image;

    // Increment hit count
    this.hitCount++;
    if (this.hitCount % 3 === 0) {
      this.currentBallSpeed += CONSTANTS.BALL_SPEED_INCREMENT;
    }

    // Calculate angle based on where it hit the paddle
    let diff = 0;
    if (ball.y < paddle.y) {
      diff = paddle.y - ball.y;
      ball.setVelocityY(-10 * diff);
    } else if (ball.y > paddle.y) {
      diff = ball.y - paddle.y;
      ball.setVelocityY(10 * diff);
    } else {
      ball.setVelocityY(2 + Math.random() * 8);
    }

    // Ensure ball speed
    const currentVelocity = ball.body!.velocity;
    const isPlayer = paddle === this.playerPaddle;

    // Normalize and scale velocity
    const newSpeed = this.currentBallSpeed;
    const direction = isPlayer ? 1 : -1;

    ball.setVelocityX(direction * newSpeed);
  }

  private handleScore(winner: 'player' | 'ai') {
    if (this.isGameOver) return;

    const store = useGameStore.getState();
    if (winner === 'player') {
      store.addPlayerScore();
      // Screen shake effect for scoring
      this.cameras.main.shake(200, 0.01);
      // Zoom text
      this.tweens.add({
        targets: this.playerScoreImg,
        scaleX: 1.5, scaleY: 1.5,
        duration: 100, yoyo: true
      });
    } else {
      store.addAiScore();
      this.cameras.main.shake(200, 0.01);
      this.tweens.add({
        targets: this.aiScoreImg,
        scaleX: 1.5, scaleY: 1.5,
        duration: 100, yoyo: true
      });
    }

    // Update displays after a short delay to allow React state to sync
    // We can also sync directly here
    const { playerScore, aiScore } = useGameStore.getState();
    this.updateScoreDisplay(playerScore, aiScore);

    if (playerScore >= CONSTANTS.WIN_SCORE || aiScore >= CONSTANTS.WIN_SCORE) {
      this.isGameOver = true;
      store.setWinner(playerScore >= CONSTANTS.WIN_SCORE ? 'player' : 'ai');
      this.ball.setVelocity(0, 0);
      this.time.delayedCall(1000, () => {
        startScene(this, 'EndScene');
      });
    } else {
      // Reset ball
      this.ball.setVelocity(0, 0);
      this.ball.setPosition(CONSTANTS.WIDTH / 2, CONSTANTS.HEIGHT / 2);
      this.time.delayedCall(1000, () => {
        this.resetBall(winner === 'player' ? -1 : 1); // Serve to the loser
      });
    }
  }

  private updateScoreDisplay(player: number, ai: number) {
    if (player !== this.lastScoreRef.player) {
      this.playerScoreImg.setFrame(Math.min(9, player));
      this.lastScoreRef.player = player;
    }
    if (ai !== this.lastScoreRef.ai) {
      this.aiScoreImg.setFrame(Math.min(9, ai));
      this.lastScoreRef.ai = ai;
    }
  }

  private resetBall(direction: number) {
    if (this.isGameOver) return;
    this.currentBallSpeed = CONSTANTS.BALL_INITIAL_SPEED;
    this.hitCount = 0;

    this.ball.setPosition(CONSTANTS.WIDTH / 2, CONSTANTS.HEIGHT / 2);
    this.ball.setVelocity(
      direction * this.currentBallSpeed, 
      (Math.random() - 0.5) * this.currentBallSpeed
    );

    // Reset paddles
    (this.playerPaddle.body as Phaser.Physics.Arcade.Body).reset(60, CONSTANTS.HEIGHT / 2);
    (this.aiPaddle.body as Phaser.Physics.Arcade.Body).reset(CONSTANTS.WIDTH - 60, CONSTANTS.HEIGHT / 2);
  }

  update() {
    if (this.isGameOver) return;

    // Player input
    const playerBody = this.playerPaddle.body as Phaser.Physics.Arcade.Body;
    if (this.cursors.up.isDown) {
      playerBody.setVelocityY(-CONSTANTS.PADDLE_SPEED);
    } else if (this.cursors.down.isDown) {
      playerBody.setVelocityY(CONSTANTS.PADDLE_SPEED);
    } else {
      playerBody.setVelocityY(0);
    }

    // Simple AI
    const aiBody = this.aiPaddle.body as Phaser.Physics.Arcade.Body;
    const aiSpeed = CONSTANTS.AI_SPEED;
    // AI only moves if the ball is moving towards it
    if (this.ball.body!.velocity.x > 0) {
      if (this.aiPaddle.y < this.ball.y - 10) {
        aiBody.setVelocityY(aiSpeed);
      } else if (this.aiPaddle.y > this.ball.y + 10) {
        aiBody.setVelocityY(-aiSpeed);
      } else {
        aiBody.setVelocityY(0);
      }
    } else {
      // Return to center slowly
      if (this.aiPaddle.y < CONSTANTS.HEIGHT / 2 - 10) {
        aiBody.setVelocityY(aiSpeed * 0.5);
      } else if (this.aiPaddle.y > CONSTANTS.HEIGHT / 2 + 10) {
        aiBody.setVelocityY(-aiSpeed * 0.5);
      } else {
        aiBody.setVelocityY(0);
      }
    }

    // Sync score if external
    const { playerScore, aiScore } = useGameStore.getState();
    this.updateScoreDisplay(playerScore, aiScore);
  }
}

import Phaser from 'phaser';
import { ASSETS } from '../assets';
import { CONSTANTS } from '../constants';
import { useGameStore } from '../model/store';
import { startScene } from '../EventBus';

export default class EndScene extends Phaser.Scene {
  constructor() {
    super('EndScene');
  }

  create() {
    const { winner, playerScore, aiScore } = useGameStore.getState();

    // Pure black background
    this.add.rectangle(0, 0, CONSTANTS.WIDTH, CONSTANTS.HEIGHT, 0x000000).setOrigin(0);

    // Board background tinted
    const board = this.add.image(CONSTANTS.WIDTH / 2, CONSTANTS.HEIGHT / 2 - 50, ASSETS.board)
      .setDisplaySize(410, 325)
      .setTintFill(0x222222); // Dark grey block

    // Text based on winner
    if (winner === 'player') {
      this.add.image(CONSTANTS.WIDTH / 2, CONSTANTS.HEIGHT / 2 - 120, ASSETS.text_win)
        .setDisplaySize(370, 95)
        .setTint(0x39FF14);
    } else {
      this.add.image(CONSTANTS.WIDTH / 2, CONSTANTS.HEIGHT / 2 - 120, ASSETS.text_lose)
        .setDisplaySize(376, 101)
        .setTint(0xFF3333);
    }

    // Final score text
    this.add.text(CONSTANTS.WIDTH / 2, CONSTANTS.HEIGHT / 2 + 20, `${playerScore} - ${aiScore}`, {
      fontFamily: 'monospace',
      fontSize: '64px',
      color: '#ffffff'
    }).setOrigin(0.5);

    // Play Again button
    const againBtn = this.add.image(CONSTANTS.WIDTH / 2, CONSTANTS.HEIGHT / 2 + 200, ASSETS.btn_again)
      .setDisplaySize(87, 174)
      .setInteractive()
      .setTintFill(0x39FF14);

    this.tweens.add({
      targets: againBtn,
      alpha: { from: 1, to: 0.5 },
      duration: 500,
      ease: 'Stepped',
      easeParams: [1],
      yoyo: true,
      repeat: -1
    });

    againBtn.on('pointerdown', () => {
      useGameStore.getState().resetGame();
      startScene(this, 'GameScene');
    });

    this.input.keyboard?.once('keydown-SPACE', () => {
      useGameStore.getState().resetGame();
      startScene(this, 'GameScene');
    });
  }
}

import Phaser from 'phaser';
import Boot from './scenes/Boot';
import StartScene from './scenes/StartScene';
import GameScene from './scenes/GameScene';
import EndScene from './scenes/EndScene';
import { CONSTANTS } from './constants';

export const config: Phaser.Types.Core.GameConfig = {
  type: Phaser.AUTO,
  parent: 'game-container',
  width: CONSTANTS.WIDTH,
  height: CONSTANTS.HEIGHT,
  scene: [Boot, StartScene, GameScene, EndScene],
  physics: {
    default: 'arcade',
    arcade: {
      gravity: { y: 0, x: 0 },
      debug: false
    }
  },
  scale: {
    mode: Phaser.Scale.FIT,
    autoCenter: Phaser.Scale.CENTER_BOTH
  },
  backgroundColor: '#000000',
  pixelArt: true // Ensures crisp rendering for pixel art aesthetics
};

